// CF01 WF_OUTLIER_SCORE — fetch topics + project context.
// Input: { project_id, force?: boolean }
// Global fetch + $env per MEMORY.md (n8n 2.8.4 task runner compat).

const input = $input.first().json;
const projectId = input.project_id;
const force = input.force === true;

if (!projectId) {
  throw new Error('WF_OUTLIER_SCORE requires { project_id } in trigger payload');
}

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

// Fetch topics — skip already-scored unless force
let topicsUrl = `${supabaseUrl}/rest/v1/topics?project_id=eq.${projectId}&select=id,seo_title,original_title,narrative_hook,topic_number&order=topic_number.asc`;
if (!force) topicsUrl += '&outlier_scored_at=is.null';

const topicsRes = await fetch(topicsUrl, { method: 'GET', headers: sbHeaders });
if (!topicsRes.ok) {
  throw new Error(`Fetch topics failed: HTTP ${topicsRes.status}: ${await topicsRes.text()}`);
}
const topics = await topicsRes.json();

// Fetch project context
const projUrl = `${supabaseUrl}/rest/v1/projects?id=eq.${projectId}&select=niche,niche_description,niche_expertise_profile`;
const projRes = await fetch(projUrl, { method: 'GET', headers: sbHeaders });
if (!projRes.ok) {
  throw new Error(`Fetch project failed: HTTP ${projRes.status}: ${await projRes.text()}`);
}
const projArr = await projRes.json();
const project = projArr[0] || {};

return [{
  json: {
    project_id: projectId,
    force,
    topics,
    topic_count: topics.length,
    niche: project.niche || '',
    niche_description: project.niche_description || '',
    niche_expertise_profile: project.niche_expertise_profile || ''
  }
}];

// Emit one item per topic, tagged with batch metadata.
// We process all batches in a single downstream Code node so rate limit
// + concurrency logic lives in one place.
const data = $input.first().json;
const topics = data.topics || [];
const BATCH_SIZE = 5;

const items = [];
for (let i = 0; i < topics.length; i += BATCH_SIZE) {
  items.push({
    json: {
      project_id: data.project_id,
      niche: data.niche,
      niche_description: data.niche_description,
      niche_expertise_profile: data.niche_expertise_profile,
      batch_index: Math.floor(i / BATCH_SIZE),
      batch: topics.slice(i, i + BATCH_SIZE),
      total_batches: Math.ceil(topics.length / BATCH_SIZE),
      total_topics: topics.length
    }
  });
}

if (items.length === 0) {
  return [{
    json: {
      project_id: data.project_id,
      skipped: true,
      reason: 'No topics pending outlier scoring (pass force=true to rescore)',
      total_topics: 0
    }
  }];
}

return items;

// CF01 per-batch scorer. Runs sequentially across topics in the batch.
// Inline exponential backoff (1s->2s->4s->8s) for YouTube + Claude calls.
// Quota exhaustion -> graceful degradation (score=50, outlier_data_available=false).

const data = $input.item.json;

if (data.skipped) return $input.item;

const batch = data.batch || [];
const projectId = data.project_id;
const niche = data.niche;
const nicheDesc = data.niche_description || niche;

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const ytKey = $env.YOUTUBE_API_KEY;
const anthropicKey = $env.ANTHROPIC_API_KEY;

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

// Track global quota state across the batch
let quotaExhausted = false;

async function fetchWithRetry(url, options, label, maxRetries = 4) {
  let lastErr = null;
  let lastStatus = 0;
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      lastStatus = res.status;
      if (res.ok) {
        return { ok: true, json: await res.json(), status: res.status, attempts: attempt };
      }
      const body = await res.text();
      // YouTube quota exceeded -> stop retrying, propagate up
      if (res.status === 403 && /quotaExceeded|dailyLimitExceeded/i.test(body)) {
        return { ok: false, quota: true, status: res.status, error: body, attempts: attempt };
      }
      // 4xx (non-quota) -> don't retry
      if (res.status >= 400 && res.status < 500 && res.status !== 429) {
        return { ok: false, status: res.status, error: body, attempts: attempt };
      }
      lastErr = new Error(`HTTP ${res.status}: ${body.slice(0, 300)}`);
    } catch (e) {
      lastErr = e;
    }
    if (attempt < maxRetries) {
      const delay = Math.min(1000 * Math.pow(2, attempt - 1), 30000);
      await sleep(delay);
    }
  }
  return { ok: false, status: lastStatus, error: lastErr?.message || `${label} failed`, attempts: maxRetries };
}

async function logProduction(topicId, action, status, durationMs, costUsd, retryCount) {
  try {
    await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
      method: 'POST',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify({
        project_id: projectId,
        topic_id: topicId,
        stage: 'outlier_score',
        scene_number: null,
        action,
        status,
        duration_ms: durationMs,
        cost_usd: costUsd,
        retry_count: retryCount
      })
    });
  } catch (_) { /* logging best-effort */ }
}

function fallbackPayload(reason) {
  return {
    outlier_score: 50,
    algorithm_momentum: 'stable',
    competing_videos_count: 0,
    outlier_ratio: 1.0,
    avg_views_top10: 0,
    outlier_reasoning: reason,
    outlier_data_available: false,
    outlier_scored_at: new Date().toISOString()
  };
}

function median(arr) {
  if (!arr.length) return 0;
  const s = [...arr].sort((a, b) => a - b);
  const m = Math.floor(s.length / 2);
  return s.length % 2 ? s[m] : Math.round((s[m - 1] + s[m]) / 2);
}

const batchResults = [];
const now30 = new Date(Date.now() - 30 * 86400000).toISOString();
const now90 = new Date(Date.now() - 90 * 86400000).toISOString();

for (const topic of batch) {
  const topicStart = Date.now();
  let retryCount = 0;

  const title = topic.seo_title || topic.original_title || '';
  if (!title) {
    const payload = fallbackPayload('Missing topic title');
    batchResults.push({ topic_id: topic.id, patch: payload, status: 'fallback_no_title' });
    continue;
  }

  if (quotaExhausted) {
    const payload = fallbackPayload('YouTube quota exhausted during this run');
    batchResults.push({ topic_id: topic.id, patch: payload, status: 'quota_exhausted' });
    await logProduction(topic.id, 'fal_ai_quota_skip', 'fallback', Date.now() - topicStart, 0, 0);
    continue;
  }

  // 1. YouTube search (last 30 days, order=viewCount, top 10)
  const searchUrl30 = `https://www.googleapis.com/youtube/v3/search?part=snippet&q=${encodeURIComponent(title)}&type=video&order=viewCount&publishedAfter=${encodeURIComponent(now30)}&maxResults=10&key=${ytKey}`;
  const search30 = await fetchWithRetry(searchUrl30, { method: 'GET' }, 'yt_search_30d');
  retryCount += (search30.attempts || 1) - 1;

  if (search30.quota) {
    quotaExhausted = true;
    const payload = fallbackPayload('YouTube quota exceeded (403 quotaExceeded)');
    batchResults.push({ topic_id: topic.id, patch: payload, status: 'quota_exhausted' });
    await logProduction(topic.id, 'yt_search_30d', 'quota_exceeded', Date.now() - topicStart, 0, retryCount);
    continue;
  }

  const items30 = search30.ok ? (search30.json?.items || []) : [];
  const videoIds = items30.map(i => i.id?.videoId).filter(Boolean).slice(0, 10);

  // 2. Older upload count (last 90d) via search.list pageInfo
  const searchUrl90 = `https://www.googleapis.com/youtube/v3/search?part=snippet&q=${encodeURIComponent(title)}&type=video&publishedAfter=${encodeURIComponent(now90)}&maxResults=1&key=${ytKey}`;
  const search90 = await fetchWithRetry(searchUrl90, { method: 'GET' }, 'yt_search_90d');
  retryCount += (search90.attempts || 1) - 1;
  if (search90.quota) { quotaExhausted = true; }
  const olderUploadCount = search90.ok ? (search90.json?.pageInfo?.totalResults || 0) : 0;
  const recentUploadCount = search30.ok ? (search30.json?.pageInfo?.totalResults || 0) : 0;

  // 3. Video stats
  let videoItems = [];
  if (videoIds.length > 0 && !quotaExhausted) {
    const videosUrl = `https://www.googleapis.com/youtube/v3/videos?part=statistics,snippet&id=${videoIds.join(',')}&key=${ytKey}`;
    const videosRes = await fetchWithRetry(videosUrl, { method: 'GET' }, 'yt_videos');
    retryCount += (videosRes.attempts || 1) - 1;
    if (videosRes.quota) quotaExhausted = true;
    if (videosRes.ok) videoItems = videosRes.json?.items || [];
  }

  if (videoItems.length === 0) {
    const payload = fallbackPayload(quotaExhausted ? 'YouTube quota exceeded' : 'No YouTube results returned for topic');
    batchResults.push({ topic_id: topic.id, patch: payload, status: 'no_yt_results' });
    await logProduction(topic.id, 'yt_videos', quotaExhausted ? 'quota_exceeded' : 'no_results', Date.now() - topicStart, 0, retryCount);
    continue;
  }

  // 4. Build search results block
  const searchResults = videoItems.map(v => ({
    title: v.snippet?.title || '',
    view_count: parseInt(v.statistics?.viewCount || '0', 10),
    published_at: v.snippet?.publishedAt || '',
    channel_title: v.snippet?.channelTitle || '',
    channel_subscriber_count: null
  }));

  const views = searchResults.map(r => r.view_count).filter(v => v > 0);
  const nicheAvgViews = median(views) || 1;

  // 5. Build Opus user prompt
  const resultsBlock = searchResults
    .map(r => `- "${r.title}" | Views: ${r.view_count} | Published: ${r.published_at} | Channel: ${r.channel_title}`)
    .join('\n');

  const userPrompt = `TOPIC ANALYSIS REQUEST

Topic: ${title}
Niche: ${nicheDesc}
Channel Niche Keywords: ${niche}

YOUTUBE SEARCH DATA (last 30 days, ordered by views):
${resultsBlock}

HISTORICAL BASELINE:
Average views per video in this niche (median of top 10): ${nicheAvgViews}
Upload frequency (videos on this topic in last 30 days): ${recentUploadCount}
Upload frequency (videos on this topic in last 90 days): ${olderUploadCount}

TASK: Return ONLY valid JSON with these fields:
{
  "outlier_score": <integer 0-100>,
  "algorithm_momentum": "<accelerating|stable|decelerating>",
  "outlier_ratio": <float capped at 20.0>,
  "avg_views_top10": <integer>,
  "competing_videos_count": <integer>,
  "reasoning": "<1-2 sentences>"
}

Scoring rubric:
- 80-100: Exceptional momentum, multiple videos >>niche avg, fast-rising.
- 60-79: Strong momentum, clear outperformers.
- 40-59: Neutral. Normal competitive landscape.
- 20-39: Weak. Few outperformers.
- 0-19: Saturated or ignored.

algorithm_momentum rules:
- accelerating: recent_upload_count / (older_upload_count/3) > 1.5 AND avg views trending up
- decelerating: opposite
- stable: neither`;

  // 6. Claude Opus 4.6
  const claudeStart = Date.now();
  const claudeRes = await fetchWithRetry('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'x-api-key': anthropicKey,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: JSON.stringify({
      model: 'claude-opus-4-6',
      max_tokens: 600,
      messages: [{ role: 'user', content: userPrompt }]
    })
  }, 'claude_opus_outlier');
  retryCount += (claudeRes.attempts || 1) - 1;

  let patch;
  if (!claudeRes.ok) {
    patch = fallbackPayload(`Claude call failed: ${claudeRes.error?.slice(0, 120) || 'unknown'}`);
    await logProduction(topic.id, 'claude_opus_outlier', 'error', Date.now() - claudeStart, 0, retryCount);
  } else {
    const text = claudeRes.json?.content?.[0]?.text || '';
    const clean = text.replace(/```json|```/g, '').trim();
    let parsed = null;
    try {
      parsed = JSON.parse(clean);
    } catch {
      const m = clean.match(/\{[\s\S]*\}/);
      if (m) { try { parsed = JSON.parse(m[0]); } catch {} }
    }
    if (!parsed || typeof parsed.outlier_score !== 'number') {
      patch = fallbackPayload('Claude response failed to parse as JSON');
      await logProduction(topic.id, 'claude_opus_outlier', 'parse_error', Date.now() - claudeStart, 0.006, retryCount);
    } else {
      // clamp + coerce
      patch = {
        outlier_score: Math.max(0, Math.min(100, Math.round(parsed.outlier_score))),
        algorithm_momentum: ['accelerating', 'stable', 'decelerating'].includes(parsed.algorithm_momentum) ? parsed.algorithm_momentum : 'stable',
        competing_videos_count: parseInt(parsed.competing_videos_count || olderUploadCount || 0, 10),
        outlier_ratio: Math.min(20.0, parseFloat(parsed.outlier_ratio || 1.0)),
        avg_views_top10: parseInt(parsed.avg_views_top10 || nicheAvgViews || 0, 10),
        outlier_reasoning: String(parsed.reasoning || parsed.outlier_reasoning || '').slice(0, 2000),
        outlier_data_available: parsed.data_unavailable ? false : true,
        outlier_scored_at: new Date().toISOString()
      };
      await logProduction(topic.id, 'claude_opus_outlier', 'success', Date.now() - claudeStart, 0.012, retryCount);
    }
  }

  batchResults.push({ topic_id: topic.id, patch, status: 'scored' });
}

// 7. PATCH all topics in this batch
for (const r of batchResults) {
  try {
    const patchRes = await fetch(`${supabaseUrl}/rest/v1/topics?id=eq.${r.topic_id}`, {
      method: 'PATCH',
      headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
      body: JSON.stringify(r.patch)
    });
    if (!patchRes.ok) {
      const t = await patchRes.text();
      r.patch_error = `HTTP ${patchRes.status}: ${t.slice(0, 200)}`;
    }
  } catch (e) {
    r.patch_error = e.message;
  }
}

// 8. Inter-batch delay (except on last batch)
if (data.batch_index + 1 < data.total_batches) {
  await sleep(2000);
}

return {
  json: {
    project_id: projectId,
    batch_index: data.batch_index,
    total_batches: data.total_batches,
    scored: batchResults.length,
    quota_exhausted: quotaExhausted,
    results: batchResults
  }
};

// Aggregate across batches.
const items = $input.all().map(i => i.json).filter(j => !j.skipped);
if (items.length === 0) {
  return [{ json: { success: true, scored_total: 0, message: 'No topics needed scoring' } }];
}

const totalScored = items.reduce((s, b) => s + (b.scored || 0), 0);
const quota = items.some(b => b.quota_exhausted);
const projectId = items[0]?.project_id;

return [{
  json: {
    success: true,
    project_id: projectId,
    scored_total: totalScored,
    batches_processed: items.length,
    quota_exhausted: quota,
    finished_at: new Date().toISOString()
  }
}];
